export class FinancialDataBucketStack extends cdk.Stack {
  constructor(scope: Construct, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // Create an S3 bucket for financial records
    const financialBucket = new s3.Bucket(this, 'FinancialDataBucket', {
      bucketName: 'financial-data-bucket', // You can use a unique name or parameter
      encryption: s3.BucketEncryption.S3_MANAGED, // Server-side encryption
      enforceSSL: true, // Ensure HTTPS is used
      accessControl: s3.BucketAccessControl.PRIVATE, // Restrict access
      removalPolicy: cdk.RemovalPolicy.RETAIN, // Retain bucket on deletion (for compliance)
      lifecycleRules: [
