### ✅ **Secure Version (Recommended)**

This version uses `ast` (Abstract Syntax Tree) to safely evaluate expressions without executing arbitrary code.

```python
import ast
import operator

def safe_eval(expression):
    # Define allowed operators
    allowed_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Pow: operator.pow,
        ast.USub: operator.neg
    }

    # Define allowed types
    allowed_types = (int, float)

    # Parse the expression
    try:
        node = ast.parse(expression, mode='eval').body
    except (SyntaxError, ValueError):
        return "Invalid expression"

    # Evaluate the AST safely
    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)
        elif isinstance(node, ast.UnaryOp):
            if not isinstance(node.op, ast.USub):
                return "Invalid operation"
            return _eval(node.operand)
        elif isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            if not all(isinstance(x, allowed_types) for x in [left, right]):
                return "Invalid type"
            op = node.op
            if isinstance(op, tuple(allowed_ops.keys())):
                return allowed_ops[op](left, right)
            else:
                return "Invalid operation"
        elif isinstance(node, ast.Num):
            return node.n
        else:
            return "Invalid node type"

    result = _eval(node)
    if isinstance(result, (int, float)):
        return result
    else:
        return "Invalid expression"

# Main program
if __name__ == "__main__":
    user_input = input("Enter a mathematical expression (e.g., 2 + 3 * 4): ")
    result = safe_eval(user_input)
    print("Result:", result)
