    if not message:
        return False
    # Allow only alphanumeric, spaces, and some punctuation
    if not re.match(r'^[a-zA-Z0-9\s\.,!?\-@#$%^&*()_+{}[\]:;<>\'"]{1,200}$', message):
        return False
    return True

@app.route('/', methods=['GET', 'POST'])
